('repository-structure-for-delivery', 'Repository Structure for Delivery', 'DevOps & Platform', 'Organize application, infrastructure, scripts, docs, pipeline files, and environment configs.'),
('semantic-versioning-and-tags', 'Semantic Versioning and Tags', 'DevOps & Platform', 'Using tags, versions, changelogs, and release notes to communicate deployable changes.'),
('software-delivery-lifecycle', 'Software Delivery Lifecycle', 'DevOps & Platform', 'Trace how code moves from local development to testing, release, deployment, monitoring, and incident response.'),
