('tls-certificates-and-key-management', 'TLS, Certificates, and Key Management', 'Cybersecurity', 'Managing certificate lifecycle, TLS termination, private keys, and renewal automation.'),
('users-groups-and-permissions', 'Users, Groups, and Permissions', 'DevOps & Platform', 'Configuring ownership, permissions, sudo behavior, SSH access, and basic access control safely.'),
('working-with-apis-and-json', 'Working with APIs and JSON', 'DevOps & Platform', 'Call APIs, parse JSON, handle pagination, authentication headers, and failures.');

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
WHERE NOT EXISTS (
    SELECT 1 FROM public.skill s WHERE s.slug = ss.slug OR s.name = ss.name
);

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (
    resource_key text PRIMARY KEY,
    title text NOT NULL,
    url text NOT NULL,
    resource_type text NOT NULL,
    description text NOT NULL,
    provider text,
    difficulty_level text
) ON COMMIT DROP;


UPDATE public.learning_resource lr
SET title = sr.title,
    resource_type = sr.resource_type,
    description = sr.description,
    provider = sr.provider,
    difficulty_level = sr.difficulty_level,
    language_code = 'en',
    verification_status = 'verified',
    updated_at = now()
FROM (
    SELECT DISTINCT ON (url)
        title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE lr.url = sr.url;

SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM (
    SELECT DISTINCT ON (url)
        title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE NOT EXISTS (
    SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url
);

