('proj-open-source-devops-contribution', 'ph-capstone', 102, 'project', NULL, NULL, NULL, 'Optional DevOps Open Source Contribution', 'Contribute docs, examples, issue reproduction, CI improvements, or small fixes to a DevOps-related open source project.', 'This project creates concrete evidence that the learner can apply the phase skills in a realistic setting.', 'side', 'ph-capstone', 15, 102, 5, 'advanced', 65, NULL, NULL, '{"source": "platform-generated", "projectType": "optional_practice"}'::jsonb, false, true, '["Build and document Optional DevOps Open Source Contribution as a portfolio-relevant DevOps deliverable.", "Validate the work with logs, commands, tests, screenshots, diagrams, or deployment evidence."]'::jsonb, '["The project has a clear README, reproducible commands, and operational notes.", "The deliverable demonstrates the relevant DevOps practices and can be reviewed by another person."]'::jsonb);

    roadmap_node_id, roadmap_version_id, parent_node_id, slug, node_type, checkpoint_type, selection_type, required_count,
    title, description, reason, order_index, layout_role, layout_group, layout_rank, layout_order,
    estimated_hours, difficulty_level, priority, position_x, position_y, metadata,
    is_required, is_trackable, learning_outcomes, completion_criteria
)
SELECT
    sn.node_id,
    m.roadmap_version_id,
    parent.node_id,
    sn.node_key,
    sn.node_type,
    sn.checkpoint_type,
    sn.selection_type,
    sn.required_count,
    sn.title,
    sn.description,
    sn.reason,
    sn.order_index,
    sn.layout_role,
    sn.layout_group,
    sn.layout_rank,
    sn.layout_order,
    sn.estimated_hours,
    sn.difficulty_level,
    sn.priority,
    sn.position_x,
    sn.position_y,
    sn.metadata,
    sn.is_required,
    sn.is_trackable,
    sn.learning_outcomes,
    sn.completion_criteria
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    position_x = EXCLUDED.position_x,
    position_y = EXCLUDED.position_y,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (
    node_key text NOT NULL,
    skill_slug text NOT NULL
) ON COMMIT DROP;



